import{_ as a,o as n,c as p,ag as i}from"./chunks/framework.eQLvDOR_.js";const c=JSON.parse('{"title":"用 LLM + Obsidian 构建个人知识库：基于 Karpathy 的“LLM Knowledge Bases”工作流","description":"","frontmatter":{"title":"用 LLM + Obsidian 构建个人知识库：基于 Karpathy 的“LLM Knowledge Bases”工作流","source":"https://x.com/yanhua1010/article/2039966047378583815","clipped_at":"2026-04-04","category":"[NotebookLM_Workflows]","tags":["llm-knowledge-base","obsidian","knowledge-compilation","karpathy","second-brain"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/NotebookLM_Workflows/NotebookLM_Workflows - 用 LLM + Obsidian 构建个人知识库：基于 Karpathy 的“LLM Knowledge Bases”工作流.md","filePath":"library/NotebookLM_Workflows/NotebookLM_Workflows - 用 LLM + Obsidian 构建个人知识库：基于 Karpathy 的“LLM Knowledge Bases”工作流.md","lastUpdated":null}'),t={name:"library/NotebookLM_Workflows/NotebookLM_Workflows - 用 LLM + Obsidian 构建个人知识库：基于 Karpathy 的“LLM Knowledge Bases”工作流.md"};function e(l,s,o,r,h,d){return n(),p("div",null,[...s[0]||(s[0]=[i(`<p>Karpathy 今天发了一条推文，讲他怎么用 LLM 构建和管理个人知识库。</p><p><img src="https://pbs.twimg.com/media/HE9kEdZaMAADLIU?format=jpg&amp;name=large" alt="Image"></p><p>我反复读了几遍。不是因为什么新概念，是因为他做的事和我这几个月在 Obsidian 里瞎折腾的东西，结构上撞了。但他用了一个词来概括，我之前一直没找到：</p><p><strong>编译（Compile）。</strong></p><p>把原始资料&quot;编译&quot;成结构化知识。Obsidian Vault 是代码仓库，LLM 是编译器。</p><p>这个类比一出来，好多之前说不清的感觉突然有名字了。</p><h2 id="你的笔记库在腐烂" tabindex="-1">你的笔记库在腐烂 <a class="header-anchor" href="#你的笔记库在腐烂" aria-label="Permalink to &quot;你的笔记库在腐烂&quot;">​</a></h2><p>我之前写过关于Obsidian + AI 的文章：</p><blockquote><p>Feb 8</p></blockquote><p>评论区里有一类反馈反复出现：</p><blockquote><p>我也在用 Obsidian，攒了几百篇笔记，但越攒越乱。我知道里面有好东西，但找不到。</p></blockquote><p>我太理解这种感觉了，因为我自己就是这样。</p><p>剪藏了一堆文章，记了不少想法，攒了很多链接。三个月后回头看，大部分变成了死文件。你记不住在哪，也记不住讲了什么。传统解法是&quot;定期整理&quot;，加标签、补链接、重新分类。我试了两周就放弃了。靠人来维护笔记库，就跟靠人来做回归测试一样，理论上可以，实际上不可能持续。</p><p>Karpathy 换了个思路：<strong>别让人整理，让 LLM 整理。</strong> 而且不是随便整理，是用软件工程的方式来搞。有输入层，有编译层，有输出层。有索引，有健康检查。</p><p><img src="https://pbs.twimg.com/media/HE9kQaYbIAAtxQL?format=jpg&amp;name=large" alt="Image"></p><h2 id="把知识库当代码仓库管" tabindex="-1">把知识库当代码仓库管 <a class="header-anchor" href="#把知识库当代码仓库管" aria-label="Permalink to &quot;把知识库当代码仓库管&quot;">​</a></h2><p>如果你写过代码，Karpathy 这套东西你会秒懂。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>软件工程          →  知识库工程</span></span>
<span class="line"><span>───────────────────────────────</span></span>
<span class="line"><span>src/             →  raw/（原始资料）</span></span>
<span class="line"><span>build/           →  wiki/（知识条目）</span></span>
<span class="line"><span>logs/            →  outputs/（问答归档）</span></span>
<span class="line"><span>编译器            →  LLM</span></span>
<span class="line"><span>IDE              →  Obsidian</span></span>
<span class="line"><span>Lint / CI        →  健康检查</span></span>
<span class="line"><span>增量编译          →  只处理新增/变更的 raw</span></span></code></pre></div><p>我是开发出身，第一眼看到这张表的反应是：这不就是 CI/CD 的知识库版本吗？</p><p>核心就三件事。</p><p><strong>分层。</strong> 原始资料、编译产物、运行时输出，三层分开。你不会把 .class 文件和 .java 文件混在一起，笔记也一样。</p><p><strong>增量。</strong> 不用每次全量重建。每天新进来几篇文章，增量编译就好。</p><p><strong>可追溯。</strong> 每个知识条目能追到原始来源，每个摘要保留原文引用。出了问题能查到根源。不是&quot;我好像在哪里看过这个说法&quot;，是&quot;来源在 raw/articles/2026-03/ 那篇里，第三段&quot;。</p><p><img src="https://pbs.twimg.com/media/HE9k0dDbcAAIbTG?format=jpg&amp;name=large" alt="Image"></p><h2 id="我的落地方案-三层目录-claude-code-当编译器" tabindex="-1">我的落地方案：三层目录 + Claude Code 当编译器 <a class="header-anchor" href="#我的落地方案-三层目录-claude-code-当编译器" aria-label="Permalink to &quot;我的落地方案：三层目录 + Claude Code 当编译器&quot;">​</a></h2><p>说完类比说实操。我把 Karpathy 的方法论落到了自己的 Vault 里，目录结构长这样：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vault/</span></span>
<span class="line"><span>├── raw/                    # 原始资料，不改</span></span>
<span class="line"><span>│   ├── articles/           # Web Clipper 剪藏</span></span>
<span class="line"><span>│   ├── podcasts/           # Podwise 导出</span></span>
<span class="line"><span>│   └── papers/             # 论文</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── wiki/                   # 编译产物，LLM 维护</span></span>
<span class="line"><span>│   ├── indexes/            # 索引（来源清单、概念清单、术语表）</span></span>
<span class="line"><span>│   ├── concepts/           # 概念条目</span></span>
<span class="line"><span>│   └── summaries/          # 逐篇摘要</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── outputs/                # 运行时输出</span></span>
<span class="line"><span>│   ├── qa/                 # 问答沉淀</span></span>
<span class="line"><span>│   └── health/             # 健康检查报告</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── x/                      # X 平台成品</span></span>
<span class="line"><span>├── 公众号/                  # 公众号成品</span></span>
<span class="line"><span>└── 小红书/                  # 小红书成品</span></span></code></pre></div><p>我保留了平台内容目录，因为我的知识库不只是研究用的，还要出内容。成品是给读者看的，wiki 是给自己看的，这两个不能混。</p><p><strong>摄取：三个入口</strong></p><ol><li><strong>Web Clipper</strong> 管网页文章。一键保存，模板里强制写入 source_url、author、published、tags。这步很重要，没有元数据的剪藏跟没剪一样。</li><li><strong>Podwise</strong> 管播客。自动转录加 AI 摘要，导出 Markdown。我之前专门写过一篇讲这个：</li><li><strong>手动剪藏</strong> 管 X 推文和零散内容。Claude Code 有个 Skill 叫 baoyu-url-to-markdown，丢个链接进去，几秒变干净的 Markdown。</li></ol><blockquote><p>Mar 17</p></blockquote><p><strong>编译：这步最关键</strong></p><p>攒了 5 到 10 篇 raw 之后，就可以做第一次&quot;编译&quot;了。在 Obsidian 里打开 Claudian，跟 Claude 说：”读一下 raw/articles/ 里最近新增的文章，为每篇生成摘要，提取概念，更新索引。” 然后让它干就行了。</p><p>具体来说干三件事：</p><p><strong>逐篇摘要。</strong> 每篇 raw 文档产出一份结构化摘要，包括核心结论、关键证据、疑点、术语。存到 wiki/summaries/。</p><p><strong>概念抽取。</strong> 从摘要里提概念，映射到 wiki/concepts/。新概念就建条目，老概念就补新证据。</p><p><strong>索引更新。</strong> 自动维护 All-Sources.md 和 All-Concepts.md。</p><p>质量怎么保证？靠 CLAUDE.md。我在里面写了编译规范：摘要的结构模板、概念条目该有哪些字段、命名规则。Claude 每次启动都读，输出就稳了。</p><p>第一次编译可能要花半小时到一小时。但跑通一次之后，后面增量编译很快，因为只处理新增的 raw。</p><p><img src="https://pbs.twimg.com/media/HE9lTKkakAAMu-A?format=jpg&amp;name=large" alt="Image"></p><h2 id="让每次对话都变成库存" tabindex="-1">让每次对话都变成库存 <a class="header-anchor" href="#让每次对话都变成库存" aria-label="Permalink to &quot;让每次对话都变成库存&quot;">​</a></h2><p>Karpathy 方法论里有一个设计我觉得特别妙：<strong>Output 落文件。</strong></p><p>以前我用 AI 的方式是：问一个问题，得到答案，关掉。下次有类似问题再问一遍。答案全在聊天记录里，等于没有。</p><p>现在改了。每次对知识库做复杂提问，结果以 Markdown 文件存到 outputs/qa/：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">question</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RAG 和轻量索引的适用边界？&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">asked_at</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-04-03</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">sources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">S-001 MotherDuck Obsidian RAG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">(/wiki/concepts/S-001%20MotherDuck%20Obsidian%20RAG)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C-042 RAG</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">(/wiki/concepts/C-042%20RAG)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># RAG vs 轻量索引</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## TL;DR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">规模在万级 note 以下，轻量索引够了。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">语义搜索需求强或规模更大，上 RAG。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 结论</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 证据</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">（链接回原始来源）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 不确定性</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>三个月下来我积累了几十份这样的 Q&amp;A 文件。它们本身就是知识条目，因为带推理过程和原始来源。下次遇到类似问题，Claude 直接读已有的 Q&amp;A，不用重新推导。</p><p>你每跟 AI 聊一次，知识库就增加一层。</p><h2 id="健康检查-给知识库做体检" tabindex="-1">健康检查：给知识库做体检 <a class="header-anchor" href="#健康检查-给知识库做体检" aria-label="Permalink to &quot;健康检查：给知识库做体检&quot;">​</a></h2><p>这步是大部分人不会想到的。</p><p>你的笔记库里有没有这些情况：同一个概念在三个地方定义不一样；某个条目只有标题没有正文；一堆笔记孤零零没有任何链接指向。</p><p>我之前也没在意。直到有一次搜到一条笔记，写的结论跟另一条完全矛盾，搞不清哪个是对的。这才意识到知识库也有&quot;技术债&quot;，不处理的话时间越长越乱。</p><p>Karpathy 的建议是定期做 Health Checks。我把它做成了每周任务，让 Claude 检查三样东西：</p><ol><li><strong>一致性。</strong> wiki/concepts/ 里有没有定义冲突？比如&quot;RAG&quot;在一个地方叫&quot;检索增强生成&quot;，另一个地方变成了&quot;向量数据库搜索&quot;。</li><li><strong>完整性。</strong> 哪些概念条目缺定义、缺例子、缺来源？</li><li><strong>孤岛。</strong> 哪些笔记入链出链都少于 2？该连到哪？</li></ol><p>报告存到 outputs/health/，每周一份。做了几周之后最大的感受是：搜到一条笔记，敢直接用了。以前还得想想：“这玩意靠谱吗”。</p><p><img src="https://pbs.twimg.com/media/HE9lveObMAAN8zu?format=jpg&amp;name=large" alt="Image"></p><h2 id="别上来就搞-rag" tabindex="-1">别上来就搞 RAG <a class="header-anchor" href="#别上来就搞-rag" aria-label="Permalink to &quot;别上来就搞 RAG&quot;">​</a></h2><p>这点必须单独说，因为太多人在这儿可能会走弯路。</p><p>一提&quot;AI + 笔记&quot;，很多人的第一反应是搭 RAG：选 Embedding 模型、搭向量数据库、调切片策略。整套架构搞了一个月，笔记库里还是只有 20 篇文章。</p><p>Karpathy 推荐这样做：知识库规模不大的时候（100 篇文章，40 万词左右），维护几个索引文件就够了。LLM 先读索引定位，再直接阅读相关内容。简单、可靠、零额外成本。</p><p>等你的笔记真的过了一万条，搜东西开始找不到、找不全了，再考虑 RAG。MotherDuck 有篇博文讲了用 DuckDB 给 Obsidian 做向量检索的完整方案，到时候再看不迟。</p><p><strong>先跑通流程，再优化基础设施。</strong> 这道理写代码的人应该都懂，但轮到自己搭知识库的时候就忘了。</p><h2 id="两周跑通最小闭环" tabindex="-1">两周跑通最小闭环 <a class="header-anchor" href="#两周跑通最小闭环" aria-label="Permalink to &quot;两周跑通最小闭环&quot;">​</a></h2><p>如果你想试，不需要什么额外工具。Obsidian + 任何你用的 LLM 就行。</p><p><strong>第一周：搭 raw → wiki 的最小循环。</strong> 建三个目录（raw / wiki / outputs），装 Web Clipper 配好模板，开始剪藏。攒够 5 到 10 篇后做第一次编译：生成摘要、提概念、建索引。</p><p><strong>第二周：让 Q&amp;A 开始积累，启动第一次健康检查。</strong> 所有复杂问答的结果存到 outputs/qa/。让 LLM 扫一遍 wiki/，输出第一份健康报告。按报告补缺失、加链接。</p><p>两周之后你有一个能持续运转的小系统。规模不重要，流程跑通了就行。后面就是往 raw/ 里不断喂素材，让编译器持续工作。</p><h2 id="知识库的-github-时刻" tabindex="-1">知识库的&quot;GitHub 时刻&quot; <a class="header-anchor" href="#知识库的-github-时刻" aria-label="Permalink to &quot;知识库的&quot;GitHub 时刻&quot;&quot;">​</a></h2><p>Karpathy 推文最后一句话是：</p><blockquote><p>这套东西目前仍然像一堆 hacky scripts，但有空间做成 incredible new product。</p></blockquote><p>我想到了 2006 年前的版本控制。那时候也是 svn、cvs、git 命令行，只有程序员在用。然后有人把它做成了 GitHub，整个协作方式都变了。</p><p>个人知识库可能正在类似的节点。今天它是 Obsidian + LLM + 手搓脚本的组合，看起来还很粗糙。但底层范式已经有了：把知识当代码来管理。有输入，有编译，有产物，有测试。</p><p>如果你是程序员，好消息是你不需要学任何新东西。代码仓库怎么管，知识库就怎么管。你积累了这么多年的工程直觉，终于可以用在自己的笔记上了。</p><p>如果你不写代码，也别被&quot;编译&quot;这个词吓住。说白了就是：让 AI 帮你定期整理笔记，而且比你自己整理得好得多。因为它不累，不忘，不偷懒。</p><p><strong>别让你的笔记腐烂。让它们被编译。</strong></p><p><strong>延伸阅读（我的 Obsidian + AI 系列）：</strong></p><ul><li><a href="https://x.com/yanhua1010/status/2020342019575673223?s=20" target="_blank" rel="noreferrer">《如何基于 Obsidian 和 Claude 打造 AI 时代超级大脑？》</a>→ 把笔记库变成内容工厂</li><li><a href="https://x.com/yanhua1010/status/2029369274847072591?s=20" target="_blank" rel="noreferrer">《Obsidian + Claude Code：你的笔记库就是你最强大的 AI 上下文》</a>→ 笔记库作为 AI 上下文的价值</li><li><a href="https://x.com/yanhua1010/status/2033726054351966613?s=20" target="_blank" rel="noreferrer">《我用 Podwise 把播客变成了可检索的知识库》</a>→ 播客信息摄取的完整流程</li></ul><p>你现在是否也在搭自己的知识库系统？</p><p>欢迎关注 --&gt; <a href="https://x.com/@yanhua1010" target="_blank" rel="noreferrer">@yanhua1010</a> , 评论区聊聊你的方案。这个领域现在很早期，说不定你的实践就是未来某个产品的原型。</p>`,78)])])}const g=a(t,[["render",e]]);export{c as __pageData,g as default};
